"""Test the signal readers. The test files are located in the resources folder and are generated by running a SIMA workflow using the Signal Generator"""
from os import path
from marmo import containers
from simapy.sima_reader import SIMAReader


def test_json():
    """Test the JSON reader."""
    file = path.join(path.dirname(__file__), "resources", "result.json")
    contents = SIMAReader().read(file)
    __check_signals(contents)

def test_s5():
    """Test the h5 reader."""
    file = path.join(path.dirname(__file__), "resources", "result.s5")
    contents = SIMAReader().read(file)
    __check_signals(contents)


def __check_signals(contents):
    assert len(contents) == 1
    container: containers.Container = contents[0]
    assert container.name == "container"
    children = container.containers
    assert len(children) == 2
    __check_constants(children[0])
    __check_arrays(children[1])


def __check_constants(constants: containers.Container):
    assert constants.name == "constants"
    signals = constants.signals
    assert len(signals) == 4
    myBoolean: containers.SimpleBoolean = signals[0]
    assert myBoolean.name == "myBoolean"
    assert myBoolean.value

    myConst: containers.DimensionalScalar = signals[1]
    assert myConst.name == "myConst"
    assert myConst.value == 10.0
    assert myConst.unit == "m"

    myInt: containers.IntegerScalar = signals[2]
    assert myInt.name == "myInt"
    assert myInt.value == 1

    myText: containers.SimpleString = signals[3]
    assert myText.name == "myText"
    assert myText.value == "s1"


def __check_arrays(arrays: containers.Container):
    assert arrays.name == "arrays"
    signals = arrays.signals
    assert len(signals) == 3

    myTexts: containers.StringArray = signals[0]
    assert myTexts.name == "myTexts"
    assert myTexts.value.tolist() == ["s1", "s2"]

    time_series: containers.EquallySpacedSignal = signals[1]
    assert time_series.name == "time_series"
    assert time_series.xstart == 10.0
    assert time_series.xdelta == 0.1
    assert time_series.value.tolist() == [1000.0, 2000.0]

    xy: containers.NonEquallySpacedSignal = signals[2]
    assert xy.name == "xy"
    assert xy.xvalue.tolist() == [1.0, 3.0]
    assert xy.value.tolist() == [2.0, 4.0]
    assert xy.xunit == "m"
    assert xy.unit == "m"
    assert xy.xlabel == "xlabel"
    assert xy.label == "ylabel"
